use crate::template::day;

fn problem_1(input: &str) -> isize {
    input
        .chars()
        .map(|c| match c {
            '(' => 1,
            ')' => -1,
            _ => 0,
        })
        .sum()
}

fn problem_2(input: &str) -> usize {
    input
        .chars()
        .map(|c| match c {
            '(' => 1_isize,
            ')' => -1,
            _ => 0,
        })
        .scan(0, |acc, x| {
            *acc += x;
            if (*acc).is_negative() {
                None
            } else {
                Some(*acc)
            }
        })
        .count()
        + 1
}

